class CatalogItem:
    def label(self):
        raise NotImplementedError("Subclasses must implement label().")

from models.base_item import CatalogItem


class Book(CatalogItem):
    def __init__(self, title, author):
        self.title = title
        self.author = author

    def label(self):
        return f"Book: {self.title} by {self.author}"

